module RefModule(
	input clk,
	input reset,
	input enable,
	input [31:0] data,
	output reg [31:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        q <= 32'b0;
    else if (enable)
        q <= data;
end
endmodule
